// Test the levenshtein logic standalone
function levenshtein\(a, b\) {
  const m = a.length, n = b.length;
  const dp = Array.from\({ length: m + 1 }, \(\) => Array\(n + 1\).fill\(0\)\);
  for \(let i = 0; i <= m; i++\) dp[i][0] = i;
  for \(let j = 0; j <= n; j++\) dp[0][j] = j;
  for \(let i = 1; i <= m; i++\) {
    for \(let j = 1; j <= n; j++\) {
      dp[i][j] = a[i - 1] === b[j - 1]
        ? dp[i - 1][j - 1]
        : 1 + Math.min\(dp[i - 1][j - 1], dp[i - 1][j], dp[i][j - 1]\);
    }
  }
  return dp[m][n];
}

const pairs = [
  ['affect', 'effect'],
  ['accept', 'except'],
  ['desert', 'dessert'],
  ['complement', 'compliment'],
  ['principal', 'principle'],
  ['import', 'export'],
  ['adapt', 'adopt'],
  ['alter', 'altar'],
];
pairs.forEach\(\([a,b]\) => console.log\(a, '↔', b, '= distance', levenshtein\(a,b\)\)\);
")
